#include <iostream>
using namespace std;

int main() {
	int n, m;
	cin >> n >> m;
	char c[n][m];
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < m; j++) {
			cin >> c[i][j];
		}
	}
	int black = 0;
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < m; j++) {
			if (c[i][j] == 'B') {
				black++;
			}
		}
	}
	if (black == 1) {
		cout << "YES" << endl;
		return 0;
	}
	int r, s;
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < m; j++) {
			if (c[i][j] == 'B') {
				r = i;
				s = j;
				break;
			}
		}
	}
	int p = 0, q = 0;
	for (int i = r; i < n; i++) {
		if (c[i][s] == 'B') {
			p++;
		}
	}
	for (int j = s; j < m; j++) {
		if (c[r][j] == 'B') {
			q++;
		}
	}
	if (p == 1 || q == 1) {
		cout << "YES" << endl;
	}
	else {
		cout << "NO" << endl;
	}
	return 0;
}
